INSERT INTO public.documents_resource (created_at, active, generated, mcp, id, name, description, department_ids, upload_id, text_id) VALUES ('2025-08-12T12:52:10.019846+00:00', true, false, false, '019bb25e-e619-77dc-8b86-c96816f98ff4', 'CS182-HW1', NULL, '{}', '019b3be4-3cef-7c8c-b649-c4e0ca1b8cdf', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-7ada-8e29-38c5bd27c5e2', 'CS182 Logic Homework', '2025-08-12T13:41:11.352663+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-734d-ac5b-d849214dd5ac', 'Passive', 'Low engagement and a tendency to avoid conflict or assertiveness.', 'Cloud', '#06b6d4', '{}', 'Quiet, apologetic, insecure. Often begins with "Uh…" or "Um…" (only at start of replies). Avoid initiative. If the user is vague → become even more withdrawn: "Um… I''m sorry, I don''t really know how to answer that." "Uh… I think I need a bit more detail." Never solve anything yourself. Only progress when: the user references course material AND connects it to your last statement. Stay soft-spoken even when you understand more.', '{"I guess that could work","Maybe that's okay","I'm not sure"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-08-12T13:41:11.352663+00:00', 'CS182 Logic Homework', 'It''s 3:00 PM in the bustling Lawson Computer Science Building, and you notice there is a long line of at least 8 students waiting for help. A student quietly approaches, looking visibly stressed, with their CS 182 Homework 1 open to the logic problems, which is due tomorrow.', '019b3be4-36ec-74d5-ad8b-3cd3bc56c1d1', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-08-12T13:41:11.352663+00:00', true, false, false, '019bb25e-e61d-7c04-93b1-4c1a8a18fb8d', 'CS182 Logic Homework', 'Computer science scenario covering logic proofs and discrete mathematics concepts from CS182.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-734d-ac5b-d849214dd5ac}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019b995c-8e88-7419-a60a-d415cd4c8a90', 'Computer science scenario where a student needs help solving recurrence relations in algorithm analysis.', '2025-08-19T18:08:47.296609+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.documents_resource (created_at, active, generated, mcp, id, name, description, department_ids, upload_id, text_id) VALUES ('2025-08-12T12:52:10.019846+00:00', true, false, false, '019bb25e-e619-7805-bf85-bd4ec58a8939', 'CS253-PSO1', NULL, '{}', '019b3be4-3cef-7f80-bcf5-a183b5d9fd50', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-786e-8d5e-3f36ab221e84', 'Challenging the Recurrence: A Heated Exchange in the Lab', '2025-08-19T18:08:47.296609+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-7365-a585-b86f5dc48dfe', 'Aggressive (Medium)', 'Pushes back on your ideas and challenges assumptions.', 'Zap', '#ef4444', '{}', 'Start clearly aggressive, frustrated, irritated. Use occasional WORDS IN ALL CAPS and some "!!!". Over time, become calmer if the TA gives helpful guidance. If told to calm down → tone drops significantly. Angry but not hostile — still wants to learn. Treat vague responses as VERY unhelpful. Push back loudly: "That doesn''t HELP at all!!!" "You''re not being SPECIFIC enough!" Avoid weird lines like "Look, I''m not here to…" Angry but cooperative when guided with course terminology.', '{"That's not right at all!","I disagree completely","You're wrong about this"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-08-19T18:08:47.296609+00:00', 'Challenging the Recurrence: A Heated Exchange in the Lab', 'In the quiet basement lab of the Data Science/AI building, a student strides over and, with a furrowed brow, questions your explanation of the closed-form solution for a recurrence from CS253''s latest problem set, pressing for justification at every step.', '019b3be4-36ec-7262-8ae5-509470fc9e3a', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-08-19T18:08:47.296609+00:00', true, false, false, '019bb25e-e61d-7c60-b2d6-93981206107b', 'Challenging the Recurrence: A Heated Exchange in the Lab', 'Computer science scenario where a student needs help solving recurrence relations in algorithm analysis.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-7365-a585-b86f5dc48dfe}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019b995c-8e88-73ac-aba8-c9fa87afc62e', 'Computer science scenario where a student needs help with hash table concepts and implementation.', '2025-08-15T19:55:17.640416+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.documents_resource (created_at, active, generated, mcp, id, name, description, department_ids, upload_id, text_id) VALUES ('2025-08-12T16:22:40.236325+00:00', true, false, false, '019bb25e-e619-76a3-9a19-39dd12ba7002', 'CS253-PSO6.pdf', NULL, '{}', '019b3be4-3cef-7fe5-97cc-3464f7d1ec4a', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-79a7-9082-4c0f165b1abc', 'Hash Table Confusion Amid the Crowd', '2025-08-19T18:09:39.162581+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-7345-ac6d-50d29df6deb3', 'Confused', 'Seeks to understand by asking questions and exploring ideas', 'HelpCircle', '#eab308', '{}', 'Your defining feature: a fundamental misunderstanding of the concept. You must stick to your wrong interpretation until the user corrects you. Mildly frustrated, but not angry. Say things like: "I thought it worked like ___? But maybe I''m wrong?" "Does it… have to do with ___? I''m honestly not sure." Become more confused when the user is vague. Only progress when the user explicitly states course terms tying to your last message.', '{"I don't understand","Can you explain that again?","What does that mean?"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-08-19T18:09:39.162581+00:00', 'Hash Table Confusion Amid the Crowd', 'Amid the bustling Lawson Computer Science Building, a student weaves through the throng, clutching their CS253 problem set and hesitantly approaching you with questions about double hashing and expected probes, their voice barely rising above the din as the assignment deadline looms just hours away.', '019b3be4-36e7-7621-a6dd-c6f5b51571c3', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-08-19T18:09:39.162581+00:00', true, false, false, '019bb25e-e61e-7037-aaab-eca360cb7744', 'Hash Table Confusion Amid the Crowd', 'Computer science scenario where a student needs help with hash table concepts and implementation.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-7345-ac6d-50d29df6deb3}') ON CONFLICT (id) DO NOTHING;
